+#[test]
+fn snprintf_normalizes_positional_negative_star_width() {
+    let mut buf = [0_i8; 64];
+
+    let written = unsafe {
+        snprintf(
+            buf.as_mut_ptr(),
+            buf.len(),
+            c"|%1$*2$d|".as_ptr(),
+            42_i32,
+            -5_i32,
+        )
+    };
+    assert_eq!(written, 7);
+
+    let out = unsafe { CStr::from_ptr(buf.as_ptr()) };
+    assert_eq!(out.to_bytes(), b"|42   |");
+}
+
+#[test]
+fn snprintf_normalizes_positional_negative_star_precision() {
+    let mut buf = [0_i8; 64];
+
+    let written = unsafe {
+        snprintf(
+            buf.as_mut_ptr(),
+            buf.len(),
+            c"%1$.*2$d".as_ptr(),
+            42_i32,
+            -1_i32,
+        )
+    };
+    assert_eq!(written, 2);
+
+    let out = unsafe { CStr::from_ptr(buf.as_ptr()) };
+    assert_eq!(out.to_bytes(), b"42");
+}
